import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyTable, mainStageHeaderAction, mainStageHeaderStrings } from '../../../../includes';
import { accountStrings } from '../../config';
import { IncomeSheetHeaderComponent } from './IncomeSheetHeaderComponent';

const style = theme => ({
    root: {
        
    }
})
class _IncomeSheet extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        mainStageHeaderAction({
            [mainStageHeaderStrings.components]: [
                IncomeSheetHeaderComponent
            ]
        })(dispatch);
    }
    
    render() {
        const {
            classes,
            [accountStrings.accountIncomes] : accountIncomes,
        } = this.props;
        return (
            <div className={classes.root}>
                <MyTable
                    header={["Name/Description", "Category", "Amount", "Date"]}
                    dataMap={["name", "category", "amount", "date"]}
                    data={accountIncomes}
                    />
            </div>
        );
    }
}


_IncomeSheet.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({accountReducer}) => ({
    [accountStrings.accountIncomes] : accountReducer[accountStrings.accountIncomes],
})


export const IncomeSheet = connect(mapStateToProps)(withStyles(style)(_IncomeSheet));