import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, MyCustomTabs } from '../../../includes';
import { IncomeSheet } from './IncomeSheet';
import { IncomeCategories } from './IncomeCategories';
import { accountActions } from '../actions';
import { routeNamesSchool } from '../../routeNames';

const style = theme => ({
    root: {
    }
})
class _Income extends Component {
    constructor(props) {
        super(props);
        this.state={
            tabValue : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "ACCOUNT (INCOME)",
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Account (income)", path : routeNamesSchool.accountIncome},
        ])(dispatch);
        mainStageHeaderAction({})(dispatch);
        
        this.setComponentContext = this.setComponentContext.bind(this);
    }
    
    setTabValue=tabValue=>{
        const {dispatch} = this.props;
        this.setState({tabValue});
        accountActions.setIncomeTabValue(tabValue)(dispatch);
    }
    setComponentContext=context=>{
        const {dispatch} = this.props;
        accountActions.setIncomeTabComponent(context)(dispatch);
    }
    render() {
        const {classes} = this.props;
        const {tabValue} = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    tabs={{
                        income : "Income",
                        cat : "Source",
                    }}
                    getInitialTabValue={this.setTabValue.bind(this)}
                    position="sticky"
                    />
                <div style={{marginTop : 20}}>
                    {tabValue === "cat" && <IncomeCategories
                        getContext={this.setComponentContext}/>}
                    {tabValue === "income" && <IncomeSheet
                        getContext={this.setComponentContext}/>}
                </div>
            </div>
        );
    }
}


_Income.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = state => ({
    state
})


export const Income = connect(mapStateToProps)(withStyles(style)(_Income));
export {Income as default};