import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { FormControl, InputLabel, Select, MenuItem, Button } from '@material-ui/core';
import { monthSelections, colors } from '../../../../../utils';
const style = theme => ({
    root: {
        marginBottom : 20,
        display : "flex"
    },
    formControl : {
        margin : 5,
    },
    grow : {
        display : "flex",
        flexGrow : 1
    }
})
//SAMPLE
const filterComponents = [
    {
        type : "select",
        name : "Year",
        value : 1, //should come from outside
        options : [
            {name : "2010", value : 1},
            {name : "2011", value : 2},
        ],
        onChange : e => console.log(e.target.value),
    }
]
class _AccountFilter extends Component {
    render() {
        const {classes, filterComponents} = this.props;
        return (
            <div className={classes.root}>
                {filterComponents && filterComponents.map((comp, index)=>{
                    if(!comp.type)throw("Filter component mush contain TYPE propperty");
                    switch(comp.type){
                        case "select" : 
                            return <FormControl key={index} className={classes.formControl}>
                                <InputLabel style={{color : "white"}}>{comp.name}</InputLabel>
                                <Select
                                    style={{
                                        color : "white"
                                    }}
                                    value={comp.value}
                                    onChange={comp.onChange}
                                    inputProps={{
                                        
                                    }}>
                                        {comp.options && comp.options.map((option, index)=>
                                            <MenuItem key={index} value={option[comp.valueProp]}>{option[comp.nameProp]}</MenuItem>
                                        )}
                                    </Select>
                            </FormControl>
                    }                    
                })}
                <div className={classes.grow}></div>
                <FormControl className={classes.formControl}>
                    <Button style={{
                        backgroundColor: colors.secondary,
                        color : colors.white
                    }} onClick={this.props.applyBtnHandler} variant="contained">
                        Apply
                    </Button>
                </FormControl>
            </div>
        );
    }
}
_AccountFilter.propTypes = {
    classes : PropTypes.object.isRequired,
    filterComponents : PropTypes.array,
    applyBtnHandler : PropTypes.func.isRequired,
};
export const AccountFilter = withStyles(style)(_AccountFilter);