import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { accountActions } from '../../actions';
import { accountStrings } from '../../config';
import { MyTable, EditableCellMapFormat, mainStageHeaderAction, mainStageHeaderStrings } from '../../../../includes';
import { AccountIncomeHeader } from './AccountIncomeHeader';


const style = theme => ({
    root: {
    }
})
class _IncomeCategories extends Component {
    constructor(props) {
        super(props);
        this.state={
            incomeCategories : null,
            incomeCategoriesUnusable : null,
        }
        const {dispatch} = props;
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                AccountIncomeHeader
            ]
        })(dispatch);
        accountActions.getAccountIncomeCategories()(dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const {
            [accountStrings.incomeCategories] : incomeCategories
        } = props;
        if(incomeCategories && JSON.stringify(incomeCategories) 
        !== JSON.stringify(state.incomeCategoriesUnusable)){
            state.incomeCategoriesUnusable = incomeCategories;
            state.incomeCategories = incomeCategories;
        }else if (state.incomeCategoriesUnusable &&
            JSON.stringify(incomeCategories) 
            !== JSON.stringify(state.incomeCategoriesUnusable)){
                state.incomeCategoriesUnusable = incomeCategories;
                state.incomeCategories = incomeCategories;
        }
        return state;
    }
    cellMapFormat=superProps=>props=><EditableCellMapFormat {...props} {...superProps}/>
    render() {
        let {
            classes,
            [accountStrings.incomeEditMode] : editMode
        } = this.props;
        let {incomeCategories} = this.state;
        let header = ["ID", "Name"];
        let dataMap = ["_id", "name"];
        if(true){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "action"];
            incomeCategories = 
                incomeCategories ? 
                    [...incomeCategories.map(
                        item=>({
                            ...item, editable : true,
                            delible : true
                        })
                    ), {new: true}] : 
                    [{new : true}]
        }
        console.log(this.props);
        return (
            <div className={classes.root}>
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    CellMap={this.cellMapFormat({
                        skipEdit: ["_id"],
                    })}
                    data={incomeCategories}
                    />
            </div>
        );
    }
}


_IncomeCategories.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({accountReducer}) => ({
    [accountStrings.incomeCategories] : accountReducer[accountStrings.incomeCategories],
    [accountStrings.incomeEditMode] : accountReducer[accountStrings.incomeEditMode],
})


export const IncomeCategories = connect(mapStateToProps)(withStyles(style)(_IncomeCategories));